const express = require('express');
const app = express();
const port = process.env.PORT || 3000;

// Built-in middleware
app.use(express.json());
app.use(express.urlencoded({ extended: true }));

// Custom middleware
app.use((req, res, next) => {
  console.log(`${new Date().toISOString()} - ${req.method} ${req.url}`);
  next();
});

// Routes
app.get('/', (req, res) => {
  res.json({ message: 'Welcome to Express!' });
});

app.get('/users', (req, res) => {
  res.json({ users: ['Alice', 'Bob', 'Charlie'] });
});

app.post('/users', (req, res) => {
  const newUser = req.body;
  res.status(201).json({ message: 'User created', user: newUser });
});

// Error handling middleware
app.use((err, req, res, next) => {
  console.error(err.stack);
  res.status(500).json({ error: 'Something went wrong!' });
});

app.listen(port, () => {
  console.log(`Express server running on port ${port}`);
});

// Route parameters
app.get('/users/:id', (req, res) => {
  const userId = req.params.id;
  res.json({ userId, message: `Fetching user ${userId}` });
});

// Multiple parameters
app.get('/users/:userId/posts/:postId', (req, res) => {
  const { userId, postId } = req.params;
  res.json({ userId, postId });
});

// Query strings
app.get('/search', (req, res) => {
  const { q, page = 1, limit = 10 } = req.query;
  res.json({ query: q, page: parseInt(page), limit: parseInt(limit) });
});

app.get('/request-info', (req, res) => {
  const requestInfo = {
    method: req.method,
    url: req.url,
    path: req.path,
    query: req.query,
    params: req.params,
    headers: req.headers,
    ip: req.ip,
    body: req.body
  };

  res.json(requestInfo);
});

// Response methods
app.get('/response-examples', (req, res) => {
  // Different response methods
  res.send('Hello World!');           // Send text
  res.json({ key: 'value' });        // Send JSON
  res.status(201).send('Created');   // Set status code
  res.redirect('/other-page');        // Redirect
  res.sendFile('path/to/file.html'); // Send file
  res.render('template', { data });  // Render template
});

// Serve static files from 'public' directory
app.use(express.static('public'));

// With cache control
app.use(express.static('public', {
  maxAge: '1d',
  etag: true,
  lastModified: true
}));

// Template engine setup (using EJS as example)
app.set('view engine', 'ejs');
app.set('views', './views');

app.get('/profile', (req, res) => {
  const user = {
    name: 'Alice',
    age: 28,
    email: 'alice@example.com'
  };
  res.render('profile', { user });
});

// routes/users.js
const express = require('express');
const router = express.Router();

router.get('/', (req, res) => {
  res.json({ users: [] });
});

router.get('/:id', (req, res) => {
  res.json({ userId: req.params.id });
});

router.post('/', (req, res) => {
  res.status(201).json({ message: 'User created' });
});

module.exports = router;

// app.js
const userRoutes = require('./routes/users');
app.use('/api/users', userRoutes);
